-- Clean load of 232 real transportistas from official data file
-- This removes all data and loads fresh from source

TRUNCATE TABLE transportistas CASCADE;

-- Insert all 232 real transportistas with correct ejecutivo assignments
ON CONFLICT (rut) DO NOTHING;

-- Verify count
SELECT 
  COUNT(*) as total_transportistas,
  COUNT(*) FILTER (WHERE ejecutivo_nombre = 'Carolina') as carolina_count,
  COUNT(*) FILTER (WHERE ejecutivo_nombre = 'Cecilia') as cecilia_count,
  COUNT(*) FILTER (WHERE ejecutivo_nombre = 'Daniela') as daniela_count,
  COUNT(*) FILTER (WHERE ejecutivo_nombre = 'Olga') as olga_count
FROM transportistas;
